import{_ as n,C as o,o as l,c as s,E as i,w as t,a as r,a0 as h}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Denmark","description":"Immigration pathways and relocation guide for Denmark","frontmatter":{"layout":"doc","title":"Moving to Denmark","description":"Immigration pathways and relocation guide for Denmark"},"headers":[],"relativePath":"europe/denmark/moving-there.md","filePath":"europe/denmark/moving-there.md","lastUpdated":null}'),d={name:"europe/denmark/moving-there.md"};function m(c,e,u,g,p,f){const a=o("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:t(()=>[...e[0]||(e[0]=[r("EU/EEA: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Non-EU: Pay Limit or Fast Track",-1)])]),_:1}),e[2]||(e[2]=h('<h1 id="moving-to-denmark" tabindex="-1">Moving to Denmark <a class="header-anchor" href="#moving-to-denmark" aria-label="Permalink to &quot;Moving to Denmark&quot;">â€‹</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">â€‹</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">â€‹</a></h3><p>Free movement applies. Register with the International House or your local municipality within 3 months. You need a valid ID and proof of employment, study, or sufficient funds.</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">â€‹</a></h3><p>Post-Brexit, UK citizens must apply for a residence permit unless covered by the Withdrawal Agreement (resided in Denmark before 31 December 2020). The same rules as third-country nationals generally apply.</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">â€‹</a></h3><ul><li><strong>Pay Limit Scheme</strong>: For jobs with an annual salary above DKK 465,000 (2025). Fast processing (3-4 weeks).</li><li><strong>Fast Track Scheme</strong>: For pre-approved companies. Work permit tied to the employer.</li><li><strong>Positive List</strong>: For occupations experiencing a shortage (e.g., IT, engineering, healthcare).</li><li><strong>Startup Denmark</strong>: For entrepreneurs with an innovative, scalable business idea.</li><li><strong>Family Reunification</strong>: For spouses or registered partners.</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">â€‹</a></h2><p>Denmark does not have a dedicated digital nomad visa. Remote workers typically use the Startup Denmark visa if they can establish a business, or the Pay Limit Scheme if employed by a Danish company. Freelancers may qualify under the self-employment route.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">â€‹</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">â€‹</a></h3><ul><li>[ ] Obtain necessary visa (non-EU)</li><li>[ ] Apply for CPR (Central Person Register) number appointment</li><li>[ ] Get health insurance (required until registered in Denmark)</li><li>[ ] Research housing (Copenhagen is expensive; Aarhus, Odense cheaper)</li><li>[ ] Gather medical records for HRT (translated to Danish or English)</li><li>[ ] Notify your bank and redirect mail</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">â€‹</a></h3><ul><li>[ ] Register at the International House / Citizen Service (within 3 months)</li><li>[ ] Receive CPR number and Yellow Card (health insurance card)</li><li>[ ] Apply for NemID/MitID (digital ID)</li><li>[ ] Open a Danish bank account</li><li>[ ] Find a GP (lĂ¦ge) â€” you can choose one after registration</li><li>[ ] Apply for a Danish SIM card</li><li>[ ] Connect with LGBT+ Denmark for community support</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">â€‹</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">â€‹</a></h3><ul><li>Monthly rent (1-bed): DKK 8,000-14,000 (Copenhagen), DKK 5,000-9,000 (other cities)</li><li>Monthly budget (single person): DKK 10,000-15,000 excluding rent</li><li>Public transport: DKK 300-600/month (Rejsekort)</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">â€‹</a></h3><p>Temperate with mild summers (15-22Â°C) and cold winters (0-5Â°C). Dark winters with very short daylight (7 hours in December).</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">â€‹</a></h3><p>Danish is the official language. English is widely spoken â€” almost all Danes are fluent. Most official forms and healthcare are available in English. Learning Danish helps with integration but is not essential for daily life in cities.</p>',22))])}const b=n(d,[["render",m]]);export{y as __pageData,b as default};
